If you are running a free tier cluster or a Flex cluster,
follow the steps in the Transportation Synonyms tab to create the collection
for a single synonym mapping definition in your index. If you have a
`M10` or higher cluster and wish to create multiple synonym
mappings in your index, follow the steps in the Multiple Synonyms tab to create
both the Transportation Synonyms and Attire Synonyms collections.Transport SynonymsCreate and populate the `transport_synonyms` collection:```c
#include <bson/bson.h>
#include <mongoc/mongoc.h>
#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[])
{
    mongoc_client_t *client;
    mongoc_database_t *database;
    mongoc_collection_t *collection;
    bson_error_t error;
    bson_t *doc;
    bool ret;

    /* Initialize the MongoDB C driver */
    mongoc_init();

    /* Create a client connection to your MongoDB cluster */
    client = mongoc_client_new("<connection-string>");
    if (!client) {
        fprintf(stderr, "Failed to create client connection.\n");
        return EXIT_FAILURE;
    }

    /* Get a handle to the sample_mflix database */
    database = mongoc_client_get_database(client, "sample_mflix");

    /* Create the transport_synonyms collection */
    collection = mongoc_database_create_collection(database, "transport_synonyms", NULL, &error);
    if (!collection) {
        fprintf(stderr, "Failed to create transport_synonyms collection: %s\n", error.message);
        return EXIT_FAILURE;
    }

    /* Create and insert the first document - equivalent mapping */
    doc = BCON_NEW(
        "mappingType", BCON_UTF8("equivalent"),
        "synonyms", "[", 
            BCON_UTF8("car"), 
            BCON_UTF8("vehicle"), 
            BCON_UTF8("automobile"), 
        "]"
    );

    ret = mongoc_collection_insert_one(collection, doc, NULL, NULL, &error);
    if (!ret) {
        fprintf(stderr, "Failed to insert document: %s\n", error.message);
    }
    bson_destroy(doc);

    /* Create and insert the second document - explicit mapping */
    doc = BCON_NEW(
        "mappingType", BCON_UTF8("explicit"),
        "input", "[", 
            BCON_UTF8("boat"), 
        "]",
        "synonyms", "[", 
            BCON_UTF8("boat"), 
            BCON_UTF8("vessel"), 
            BCON_UTF8("sail"), 
        "]"
    );

    ret = mongoc_collection_insert_one(collection, doc, NULL, NULL, &error);
    if (!ret) {
        fprintf(stderr, "Failed to insert document: %s\n", error.message);
    }
    bson_destroy(doc);

    /* Release the collection handle */
    mongoc_collection_destroy(collection);

    /* Clean up resources */
    mongoc_database_destroy(database);
    mongoc_client_destroy(client);
    mongoc_cleanup();

    printf("Synonyms collections successfully created and populated.\n");

    return EXIT_SUCCESS;
}

